async function loadDashboard(){try{const t=await apiFetch("GET","/team");teamData=t,$("sd-players").textContent=t.length}catch(t){}}function showLastMatchBanner(t){if(!t)return;$("dash-last-score").textContent=t.score||"?";const a=(t.message||"").includes("Vyhr"),e=(t.message||"").includes("Rem");$("dash-last-result").textContent=a?"VÝHRA":e?"REMÍZA":"PROHRA",$("dash-last").style.display="flex"}